from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('mongodb://localhost:27017/')
db = client['content_management_system']
users_collection = db['users']

@app.route('/user', methods=['POST'])
def create_user():
    user_data = request.json
    # Validate input
    if not all(key in user_data for key in ['username', 'email']):
        return jsonify({'error': 'Missing required fields'}), 400
    
    # Insert user document
    result = users_collection.insert_one(user_data)
    return jsonify({'user_id': str(result.inserted_id)}), 201

@app.route('/user/<user_id>', methods=['GET'])
def get_user(user_id):
    user = users_collection.find_one({'_id': user_id})
    if not user:
        return jsonify({'error': 'User not found'}), 404
    return jsonify(user)

@app.route('/users', methods=['GET'])
def list_users():
    users = list(users_collection.find())
    return jsonify(users)

@app.route('/user/<user_id>/documents', methods=['POST'])
def create_document(user_id):
    document_data = request.json
    # Validate input
    if not all(key in document_data for key in ['title', 'content']):
        return jsonify({'error': 'Missing required fields'}), 400
    
    # Insert document with user reference
    document_data['user_id'] = user_id
    result = users_collection.insert_one(document_data)
    return jsonify({'document_id': str(result.inserted_id)}), 201

@app.route('/documents', methods=['GET'])
def list_documents():
    documents = list(users_collection.find({}, {'_id': 0, 'title': 1, 'content': 1}))
    return jsonify(documents)

if __name__ == '__main__':
    app.run(debug=True)